#include <stdio.h>
#include <string.h>
#include <stdbool.h>

typedef struct {
    char a[5];
    int b;
    int c;
} Query;

bool compare(int num, Query* queries, int n) {
    char digits[5];
    sprintf(digits, "%04d", num);

    // Check all digits are unique
    for (int i = 0; i < 4; i++) {
        for (int j = i + 1; j < 4; j++) {
            if (digits[i] == digits[j]) {
                return false;
            }
        }
    }

    for (int q = 0; q < n; q++) {
