            for (int j = 0; j < 4; j++) {
                if (queries[q].a[i] == digits[j]) {
                    n_total++;
                    break;
                }
            }
        }
        n_total -= m;
        if (m != queries[q].b || n_total != queries[q].c) {
            return false;
        }
    }
    return true;
}

